# result = binary_search(arr, 7, 0, 6)  # Returns 3

public class MedianOfMedians {

    public static int select(int[] arr, int k) {
        return selectHelper(arr, 0, arr.length - 1, k);
    }

    private static int selectHelper(int[] arr, int left, int right, int k) {
        if (left == right) return arr[left];

        // Divide: find median of medians
        int pivot = findMedianOfMedians(arr, left, right);

        // Partition around pivot
        int pivotIndex = partition(arr, left, right, pivot);

        // Conquer: recurse to appropriate part
        if (k == pivotIndex) return arr[k];
        else if (k < pivotIndex) return selectHelper(arr, left, pivotIndex - 1, k);
        else return selectHelper(arr, pivotIndex + 1, right, k);
    }

    private static int findMedianOfMedians(int[] arr, int left, int right) {
        int n = right - left + 1;
        int numMedians = (n + 4) / 5;
        int[] medians = new int[numMedians];

        for (int i = 0; i < numMedians; i++) {
            int groupLeft = left + i * 5;
            int groupRight = Math.min(groupLeft + 4, right);
            medians[i] = findMedian(arr, groupLeft, groupRight);
        }

        return selectHelper(medians, 0, numMedians - 1, numMedians / 2);
    }

